import{_ as t,c as o,o as a,ae as i}from"./chunks/framework.CDjunVez.js";const u=JSON.parse('{"title":"PHP Version Management","description":"","frontmatter":{},"headers":[],"relativePath":"features/phpmanage.md","filePath":"features/phpmanage.md"}'),r={name:"features/phpmanage.md"};function s(n,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="php-version-management" tabindex="-1">PHP Version Management <a class="header-anchor" href="#php-version-management" aria-label="Permalink to &quot;PHP Version Management&quot;">​</a></h1><p>KiwiPanel lets you manage each installed PHP version from a single page. Monitor worker processes, tune LSAPI performance, edit php.ini directives, manage extensions, and view logs — all from <strong>Settings → Services → PHP X.Y</strong>.</p><p>Navigate to <strong>Settings → Services</strong> and click on a PHP version to open the management page.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>This page manages <strong>server-wide</strong> settings that affect all websites using a given PHP version. For per-website PHP settings (memory limit, error handling, open_basedir, etc.), see <a href="/website/phpsetting.html">PHP Settings</a>.</p></div><hr><h2 id="tabs-overview" tabindex="-1">Tabs Overview <a class="header-anchor" href="#tabs-overview" aria-label="Permalink to &quot;Tabs Overview&quot;">​</a></h2><p>The PHP management page has six tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Service</strong></td><td>Binary status, active worker processes, memory usage</td></tr><tr><td><strong>Extensions</strong></td><td>Install, remove, and view PHP extensions</td></tr><tr><td><strong>Configuration</strong></td><td>Edit php.ini directives (resource limits, OPcache, sessions, etc.)</td></tr><tr><td><strong>LSAPI Tuning</strong></td><td>OpenLiteSpeed LSAPI performance settings</td></tr><tr><td><strong>phpinfo</strong></td><td>Full <code>phpinfo()</code> output for this PHP version</td></tr><tr><td><strong>Logs</strong></td><td>Recent PHP error log entries</td></tr></tbody></table><hr><h2 id="service" tabindex="-1">Service <a class="header-anchor" href="#service" aria-label="Permalink to &quot;Service&quot;">​</a></h2><p>The Service tab shows real-time status for the selected PHP version:</p><ul><li><strong>Binary path</strong> — where the lsphp binary is located (e.g., <code>/usr/local/lsws/lsphp84/bin/lsphp</code>)</li><li><strong>Active workers</strong> — number of running lsphp processes</li><li><strong>Total memory</strong> — combined memory usage of all workers</li><li><strong>Websites using</strong> — how many websites are configured to use this version</li></ul><h3 id="worker-processes-table" tabindex="-1">Worker Processes Table <a class="header-anchor" href="#worker-processes-table" aria-label="Permalink to &quot;Worker Processes Table&quot;">​</a></h3><p>Each active worker is listed with:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>PID</td><td>Process ID</td></tr><tr><td>Memory</td><td>RSS memory usage</td></tr><tr><td>CPU</td><td>Current CPU percentage</td></tr><tr><td>Uptime</td><td>How long the process has been running</td></tr></tbody></table><h3 id="restart-workers" tabindex="-1">Restart Workers <a class="header-anchor" href="#restart-workers" aria-label="Permalink to &quot;Restart Workers&quot;">​</a></h3><p>Click <strong>Restart Workers</strong> in the top-right corner to kill all lsphp processes for this version. OpenLiteSpeed will respawn them on the next request. Use this after making configuration changes or if workers are misbehaving.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Restarting workers terminates in-flight PHP requests. Do this during low-traffic periods.</p></div><hr><h2 id="extensions" tabindex="-1">Extensions <a class="header-anchor" href="#extensions" aria-label="Permalink to &quot;Extensions&quot;">​</a></h2><p>View all available and installed extensions for this PHP version.</p><p>Each extension shows:</p><table tabindex="0"><thead><tr><th>Badge</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Bundled</strong> (green)</td><td>Built into PHP core — cannot be removed</td></tr><tr><td><strong>Installed</strong> (blue)</td><td>Installed via package manager — can be removed</td></tr><tr><td><strong>Available</strong> (gray)</td><td>Not installed — can be installed</td></tr></tbody></table><h3 id="installing-an-extension" tabindex="-1">Installing an Extension <a class="header-anchor" href="#installing-an-extension" aria-label="Permalink to &quot;Installing an Extension&quot;">​</a></h3><ol><li>Find the extension in the list</li><li>Click <strong>Install</strong></li><li>Wait for the package installation to complete</li><li>The extension is immediately available (workers restart automatically)</li></ol><h3 id="removing-an-extension" tabindex="-1">Removing an Extension <a class="header-anchor" href="#removing-an-extension" aria-label="Permalink to &quot;Removing an Extension&quot;">​</a></h3><ol><li>Find the installed extension</li><li>Click <strong>Remove</strong></li><li>Confirm the removal</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Extension management uses the system package manager (<code>apt</code> on Debian/Ubuntu, <code>dnf</code> on RHEL/AlmaLinux). The extension packages follow the naming convention <code>lsphpXY-{ext}</code> (e.g., <code>lsphp84-redis</code>).</p></div><h3 id="commonly-needed-extensions" tabindex="-1">Commonly Needed Extensions <a class="header-anchor" href="#commonly-needed-extensions" aria-label="Permalink to &quot;Commonly Needed Extensions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Extension</th><th>Use Case</th></tr></thead><tbody><tr><td>gd / imagick</td><td>Image processing (WordPress thumbnails, etc.)</td></tr><tr><td>intl</td><td>Internationalization (number/date formatting)</td></tr><tr><td>mbstring</td><td>Multibyte string handling (UTF-8, CJK)</td></tr><tr><td>redis</td><td>Redis caching (WordPress object cache, Laravel)</td></tr><tr><td>curl</td><td>HTTP requests to external APIs</td></tr><tr><td>zip</td><td>Archive handling</td></tr><tr><td>bcmath</td><td>Precise math (e-commerce, financial apps)</td></tr><tr><td>soap</td><td>SOAP web services</td></tr></tbody></table><hr><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Edit PHP directives that apply server-wide to all websites running this PHP version.</p><p>The Configuration tab has two modes:</p><ul><li><strong>Form mode</strong> (default) — organized settings with dropdowns and inputs</li><li><strong>Raw mode</strong> — direct ini file editing with syntax highlighting (Ace editor)</li></ul><p>Toggle between modes using the <strong>Form / Raw</strong> switch in the top-right corner.</p><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>Raw mode changes can break PHP for all websites using this version. Always prefer form mode unless you need directives not available in the form.</p></div><h3 id="resource-limits" tabindex="-1">Resource Limits <a class="header-anchor" href="#resource-limits" aria-label="Permalink to &quot;Resource Limits&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directive</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>memory_limit</code></td><td>256M</td><td>Maximum memory per script. Increase for heavy applications.</td></tr><tr><td><code>max_execution_time</code></td><td>30</td><td>Maximum seconds before a script is killed.</td></tr><tr><td><code>max_input_time</code></td><td>60</td><td>Maximum seconds to parse request data.</td></tr><tr><td><code>max_input_vars</code></td><td>1000</td><td>Maximum number of input variables. Increase for complex forms.</td></tr></tbody></table><h3 id="file-upload" tabindex="-1">File Upload <a class="header-anchor" href="#file-upload" aria-label="Permalink to &quot;File Upload&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directive</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>upload_max_filesize</code></td><td>64M</td><td>Maximum size of a single uploaded file.</td></tr><tr><td><code>post_max_size</code></td><td>64M</td><td>Maximum size of the entire POST body. Must be ≥ <code>upload_max_filesize</code>.</td></tr><tr><td><code>max_file_uploads</code></td><td>20</td><td>Maximum simultaneous file uploads per request.</td></tr><tr><td><code>file_uploads</code></td><td>On</td><td>Enable or disable file uploads entirely.</td></tr></tbody></table><h3 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directive</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>display_errors</code></td><td>Off</td><td>Show errors on web pages. <strong>Never enable in production.</strong></td></tr><tr><td><code>display_startup_errors</code></td><td>Off</td><td>Show errors during PHP startup.</td></tr><tr><td><code>error_reporting</code></td><td><code>E_ALL &amp; ~E_DEPRECATED &amp; ~E_STRICT</code></td><td>Which error types to report.</td></tr><tr><td><code>log_errors</code></td><td>On</td><td>Write errors to the log file.</td></tr><tr><td><code>error_log</code></td><td><code>/var/log/lsws/php_error.log</code></td><td>Path to the error log file.</td></tr></tbody></table><h3 id="session" tabindex="-1">Session <a class="header-anchor" href="#session" aria-label="Permalink to &quot;Session&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directive</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>session.gc_maxlifetime</code></td><td>1440</td><td>Seconds before session data expires (24 minutes).</td></tr><tr><td><code>session.cookie_lifetime</code></td><td>0</td><td>Cookie lifetime. <code>0</code> = expires when browser closes.</td></tr><tr><td><code>session.save_handler</code></td><td>files</td><td>Session storage backend.</td></tr><tr><td><code>session.save_path</code></td><td><code>/var/lib/php/sessions</code></td><td>Directory for session files.</td></tr></tbody></table><h3 id="opcache" tabindex="-1">OPcache <a class="header-anchor" href="#opcache" aria-label="Permalink to &quot;OPcache&quot;">​</a></h3><p>OPcache dramatically improves PHP performance by caching compiled bytecode in shared memory.</p><table tabindex="0"><thead><tr><th>Directive</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>opcache.enable</code></td><td>1</td><td>Enable the opcode cache. <strong>Always keep enabled in production.</strong></td></tr><tr><td><code>opcache.memory_consumption</code></td><td>128</td><td>Memory allocated for caching (MB). Must not exceed 75% of total server RAM.</td></tr><tr><td><code>opcache.max_accelerated_files</code></td><td>10000</td><td>Maximum number of PHP files to cache. Increase for large codebases.</td></tr><tr><td><code>opcache.validate_timestamps</code></td><td>1</td><td>Check if files changed since caching. Disable for maximum performance on production.</td></tr><tr><td><code>opcache.revalidate_freq</code></td><td>2</td><td>How often (seconds) to check for file changes when <code>validate_timestamps</code> is on.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">OPcache Memory Limit</p><p>KiwiPanel validates that <code>opcache.memory_consumption</code> does not exceed 75% of your server&#39;s total RAM. Setting it too high can OOM-crash all lsphp processes. On a 2GB VPS, the maximum is 1536MB.</p></div><div class="tip custom-block"><p class="custom-block-title">OPcache for Production</p><p>For maximum performance on production servers where you deploy code via git/CI (not editing files live):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opcache.validate_timestamps = 0</span></span>
<span class="line"><span>opcache.revalidate_freq = 0</span></span></code></pre></div><p>Then restart workers after each deployment to pick up new code.</p></div><h3 id="date-timezone" tabindex="-1">Date / Timezone <a class="header-anchor" href="#date-timezone" aria-label="Permalink to &quot;Date / Timezone&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Directive</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>date.timezone</code></td><td>UTC</td><td>Default timezone for <code>date()</code>, <code>strtotime()</code>, etc.</td></tr></tbody></table><h3 id="security-disabled-functions" tabindex="-1">Security &amp; Disabled Functions <a class="header-anchor" href="#security-disabled-functions" aria-label="Permalink to &quot;Security &amp; Disabled Functions&quot;">​</a></h3><p>This section shows security directives and the current <code>disable_functions</code> list. The active security preset badge (Standard, Relaxed, None, Custom) is displayed in the card header.</p><table tabindex="0"><thead><tr><th>Directive</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>expose_php</code></td><td>Off</td><td>Hide <code>X-Powered-By</code> header. Keep Off to prevent version fingerprinting.</td></tr><tr><td><code>allow_url_fopen</code></td><td>On</td><td>Allow <code>fopen()</code> to access URLs. Required by many frameworks.</td></tr><tr><td><code>allow_url_include</code></td><td>Off</td><td>Allow <code>include()</code> to load remote URLs. <strong>Never enable</strong> — major RCE vector.</td></tr><tr><td><code>disable_functions</code></td><td><em>(preset)</em></td><td>Comma-separated list of blocked PHP functions.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The <code>disable_functions</code> list on this page shows the value from the global drop-in ini. The <strong>security preset</strong> (Standard, Relaxed, None, Custom) configured at <a href="./phpsecurity.html">Settings → PHP Security</a> takes precedence via a separate drop-in file that loads after this one. To change the preset, go to <strong>Settings → PHP Security</strong>.</p></div><h3 id="how-configuration-is-stored" tabindex="-1">How Configuration Is Stored <a class="header-anchor" href="#how-configuration-is-stored" aria-label="Permalink to &quot;How Configuration Is Stored&quot;">​</a></h3><p>KiwiPanel writes global PHP configuration to a drop-in ini file in the PHP scan directory:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RHEL/AlmaLinux:  /usr/local/lsws/lsphp84/etc/php.d/00-kiwipanel.ini</span></span>
<span class="line"><span>Debian/Ubuntu:   /usr/local/lsws/lsphp84/etc/php/8.4/mods-available/00-kiwipanel.ini</span></span></code></pre></div><p>The <code>00-</code> prefix ensures it loads <strong>first</strong> in the scan directory, before:</p><ul><li><code>10-opcache.ini</code> (distro OPcache defaults)</li><li><code>20-kiwipanel-security.ini</code> (security directives from PHP Security page)</li></ul><p>Security-managed directives (<code>disable_functions</code>, <code>expose_php</code>, <code>allow_url_include</code>) in <code>00-kiwipanel.ini</code> are overridden by the security drop-in (<code>20-kiwipanel-security.ini</code>) which loads later.</p><details class="details custom-block"><summary>Why not php.ini?</summary><p>OpenLiteSpeed&#39;s lsphp processes do not load the main <code>php.ini</code> file. They only read from the scan directory (<code>php.d/</code> or <code>mods-available/</code>). KiwiPanel writes to a drop-in ini file in the scan directory to ensure directives actually take effect for web requests.</p><p>The CLI <code>php</code> command does load <code>php.ini</code>, so <code>php -i</code> may show different values than what your websites use. Always verify settings via a web-accessible <code>phpinfo()</code> page.</p></details><hr><h2 id="lsapi-tuning" tabindex="-1">LSAPI Tuning <a class="header-anchor" href="#lsapi-tuning" aria-label="Permalink to &quot;LSAPI Tuning&quot;">​</a></h2><p>LSAPI (LiteSpeed Server Application Programming Interface) controls how OpenLiteSpeed communicates with PHP processes. These settings affect performance, concurrency, and resource usage.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>These are <strong>default values</strong> for new websites. Click <strong>Apply to All</strong> to update existing websites using this PHP version.</p></div><h3 id="worker-processes" tabindex="-1">Worker Processes <a class="header-anchor" href="#worker-processes" aria-label="Permalink to &quot;Worker Processes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Max Connections</td><td>35</td><td>Maximum concurrent connections to the PHP backend.</td></tr><tr><td>LSAPI Children</td><td>35</td><td>Number of PHP child processes per website. Higher values handle more concurrent requests but use more RAM.</td></tr><tr><td>LSAPI Avoid Fork</td><td>200M</td><td>Memory threshold before OLS avoids forking new PHP processes.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Sizing PHP Workers</p><p>A rough formula: each PHP worker uses ~30-80MB of RAM depending on your application. On a 2GB VPS:</p><ul><li>Conservative: 10-15 children</li><li>Moderate: 20-25 children</li><li>Aggressive: 30-35 children</li></ul><p>Monitor actual memory usage in the Service tab and adjust accordingly.</p></div><h3 id="timeouts" tabindex="-1">Timeouts <a class="header-anchor" href="#timeouts" aria-label="Permalink to &quot;Timeouts&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Init Timeout</td><td>60 sec</td><td>Maximum time to wait for a new PHP process to start.</td></tr><tr><td>Retry Timeout</td><td>0 sec</td><td>Delay before retrying a failed connection to PHP.</td></tr><tr><td>Keep-Alive Timeout</td><td>15 sec</td><td>How long to keep an idle persistent connection alive.</td></tr></tbody></table><h3 id="memory-limits" tabindex="-1">Memory Limits <a class="header-anchor" href="#memory-limits" aria-label="Permalink to &quot;Memory Limits&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Soft Limit</td><td>0 MB</td><td>Memory threshold that triggers a graceful restart of the PHP process. <code>0</code> = no limit.</td></tr><tr><td>Hard Limit</td><td>0 MB</td><td>Absolute memory cap — the process is killed immediately if exceeded. <code>0</code> = no limit.</td></tr></tbody></table><h3 id="process-limits" tabindex="-1">Process Limits <a class="header-anchor" href="#process-limits" aria-label="Permalink to &quot;Process Limits&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Proc Soft Limit</td><td>400</td><td>Soft limit on number of processes.</td></tr><tr><td>Proc Hard Limit</td><td>500</td><td>Hard limit — new processes are rejected beyond this.</td></tr></tbody></table><h3 id="other" tabindex="-1">Other <a class="header-anchor" href="#other" aria-label="Permalink to &quot;Other&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Persist Connection</td><td>On</td><td>Keep connections to PHP processes alive between requests. <strong>Keep enabled</strong> for performance.</td></tr><tr><td>Response Buffer</td><td>Off</td><td>Buffer the full response before sending to the client.</td></tr><tr><td>Auto Start</td><td>2</td><td>How OLS starts PHP processes (0=off, 1=on, 2=detect, 3=always).</td></tr><tr><td>Backlog</td><td>100</td><td>Maximum pending connection queue length.</td></tr><tr><td>Instances</td><td>1</td><td>Number of PHP backend instances. Usually 1 is sufficient.</td></tr><tr><td>Run On Startup</td><td>3</td><td>Pre-start PHP processes when OLS starts.</td></tr></tbody></table><hr><h2 id="phpinfo" tabindex="-1">phpinfo <a class="header-anchor" href="#phpinfo" aria-label="Permalink to &quot;phpinfo&quot;">​</a></h2><p>Displays the full <code>phpinfo()</code> output for this PHP version in an iframe. This shows:</p><ul><li>Loaded configuration files</li><li>All active directives and their values</li><li>Installed extensions with their settings</li><li>Environment variables</li><li>HTTP headers</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use this tab to verify that configuration changes from the Configuration tab are actually taking effect. Look for your directive in the &quot;Core&quot; or relevant extension section.</p></div><hr><h2 id="logs" tabindex="-1">Logs <a class="header-anchor" href="#logs" aria-label="Permalink to &quot;Logs&quot;">​</a></h2><p>Shows recent PHP error log entries for this version. The log file path depends on the <code>error_log</code> directive in the Configuration tab (default: <code>/var/log/lsws/php_error.log</code>).</p><p>Use this tab to:</p><ul><li>Debug PHP errors without SSH access</li><li>Check for deprecation warnings after a PHP upgrade</li><li>Spot security-related warnings</li></ul><hr><h2 id="global-vs-per-website-settings" tabindex="-1">Global vs Per-Website Settings <a class="header-anchor" href="#global-vs-per-website-settings" aria-label="Permalink to &quot;Global vs Per-Website Settings&quot;">​</a></h2><p>Understanding which settings apply where:</p><table tabindex="0"><thead><tr><th>Scope</th><th>What it controls</th><th>Where to configure</th></tr></thead><tbody><tr><td><strong>Global (this page)</strong></td><td>Server-wide php.ini defaults, OPcache tuning, LSAPI performance, extensions</td><td>Settings → Services → PHP X.Y</td></tr><tr><td><strong>Global security</strong></td><td><code>disable_functions</code>, <code>expose_php</code>, <code>allow_url_include</code>, session hardening, chroot</td><td><a href="./phpsecurity.html">Settings → PHP Security</a></td></tr><tr><td><strong>Per-website</strong></td><td><code>memory_limit</code>, <code>max_execution_time</code>, upload sizes, error handling, <code>open_basedir</code></td><td><a href="/website/phpsetting.html">Websites → (site) → PHP</a></td></tr></tbody></table><p><strong>Precedence order</strong> (later overrides earlier):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>php.ini (OS defaults)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>00-kiwipanel.ini (global config — this page)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>10-opcache.ini (distro OPcache defaults)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>20-kiwipanel-security.ini (security presets)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>OLS vhost phpIniOverride (per-website settings)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>.user.ini (user overrides — limited to PHP_INI_USER)</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">PHP_INI_SYSTEM vs PHP_INI_ALL</p><p>Directives marked <code>PHP_INI_SYSTEM</code> (like <code>opcache.memory_consumption</code>, <code>disable_functions</code>) can only be set at the server level — they are read once when lsphp starts and cannot be overridden per-website.</p><p>Directives marked <code>PHP_INI_ALL</code> or <code>PHP_INI_PERDIR</code> (like <code>memory_limit</code>, <code>display_errors</code>) can be overridden per-website via the website&#39;s PHP settings page.</p></div><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="changes-not-taking-effect" tabindex="-1">Changes not taking effect <a class="header-anchor" href="#changes-not-taking-effect" aria-label="Permalink to &quot;Changes not taking effect&quot;">​</a></h3><ol><li>After saving, KiwiPanel kills lsphp workers so they restart with the new config. If values still look old, click <strong>Restart Workers</strong> manually.</li><li>Check the <strong>phpinfo</strong> tab to verify the directive shows the expected value.</li><li>If <code>phpinfo</code> shows the old value, the directive may be overridden by a later-loading ini file or per-website setting. Check the &quot;Configuration File (php.ini) Path&quot; and &quot;Additional .ini files parsed&quot; sections in phpinfo.</li></ol><h3 id="opcache-memory-rejected" tabindex="-1">OPcache memory rejected <a class="header-anchor" href="#opcache-memory-rejected" aria-label="Permalink to &quot;OPcache memory rejected&quot;">​</a></h3><p>KiwiPanel limits <code>opcache.memory_consumption</code> to 75% of total server RAM to prevent OOM crashes. If you need more, consider upgrading your server&#39;s RAM.</p><h3 id="extensions-fail-to-install" tabindex="-1">Extensions fail to install <a class="header-anchor" href="#extensions-fail-to-install" aria-label="Permalink to &quot;Extensions fail to install&quot;">​</a></h3><ol><li>Check that your server has internet access</li><li>The LiteSpeed PHP repository must be configured. KiwiPanel sets this up during installation.</li><li>On RHEL/AlmaLinux, run <code>dnf module disable php</code> first — the default PHP module can filter out <code>lsphp*</code> packages.</li></ol><h3 id="worker-memory-keeps-growing" tabindex="-1">Worker memory keeps growing <a class="header-anchor" href="#worker-memory-keeps-growing" aria-label="Permalink to &quot;Worker memory keeps growing&quot;">​</a></h3><p>PHP workers can accumulate memory over time (memory leaks in application code or extensions). Set a <strong>Memory Soft Limit</strong> in the LSAPI Tuning tab to automatically recycle workers that exceed the threshold.</p><h3 id="phpinfo-shows-different-values-than-cli" tabindex="-1">phpinfo shows different values than CLI <a class="header-anchor" href="#phpinfo-shows-different-values-than-cli" aria-label="Permalink to &quot;phpinfo shows different values than CLI&quot;">​</a></h3><p>This is expected. The CLI <code>php</code> command loads <code>php.ini</code> directly, while web-facing lsphp processes load from the scan directory. Always trust the phpinfo output from the <strong>phpinfo</strong> tab (or a web-accessible <code>phpinfo()</code> page) — that shows what your websites actually see.</p>`,107)])])}const m=t(r,[["render",s]]);export{u as __pageData,m as default};
